    if re.search(r'[a-z]', password):
        score += 1
    else:
        failed_rules.append("BR-003")

    # BR-004: Password must contain at least one digit
    if re.search(r'\d', password):
        score += 1
    else:
        failed_rules.append("BR-004")

    # BR-005: Password must contain at least one special character (!@#$%^&*)
    # Strictly adhering to the specified characters using a regular expression.
    if re.search(r'[!@#$%^&*]', password):
        score += 1
    else:
        failed_rules.append("BR-005")

